#include <stdio.h>
int main() {
    int T, n;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &n);
        int q[n][n-1];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n-1; j++) {
                scanf("%d", &q[i][j]);
            }
        }
        int p[n];
        for (int i = 0; i < n; i++) {
            int found = 0;
            for (int j = 0; j < n-1; j++) {
                if (q[i][j] != q[(i+1)%n][j]) {
                    p[i] = q[i][j];
                    found = 1;
                    break;
                }
            }
            if (!found) {
                p[i] = n;
            }
        }
        for (int i = 0; i < n; i++) {
            printf("%d ", p[i]);
        }
        printf("\n");
    }
    return 0;
}

