import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[][] q = new int[n][n-1];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n-1; j++) {
                    q[i][j] = sc.nextInt();
                }
            }
            int[] p = new int[n];
            for (int i = 0; i < n; i++) {
                int found = 0;
                for (int j = 0; j < n-1; j++) {
                    if (q[i][j] != q[(i+1)%n][j]) {
                        p[i] = q[i][j];
                        found = 1;
                        break;
                    }
                }
                if (found == 0) {
                    p[i] = n;
                }
            }
            for (int i = 0; i < n; i++) {
                System.out.print(p[i] + " ");
            }
            System.out.println();
        }
    }
}

